//! Integration tests comparing rustfoil-solver viscous results with XFOIL.
//!
//! These tests validate that the viscous solver integration with rustfoil-inviscid
//! produces results matching XFOIL's VISCAL.
//!
//! Reference data is generated by `scripts/extract_viscous_reference.py`.

use serde::Deserialize;
use std::fs::File;
use std::io::BufReader;
use std::path::Path;

// Import the solver types
use rustfoil_solver::viscous::{
    setup_from_coords, interpolate_stagnation, compute_arc_lengths, ViscousSetupResult,
};

/// Reference data structure matching viscous_ref.json
#[derive(Debug, Deserialize)]
struct ViscousReference {
    test: String,
    source: String,
    n_panels: usize,
    reynolds: f64,
    mach: f64,
    ncrit: f64,
    airfoil: String,
    #[serde(default)]
    stagnation_base: Option<StagnationRef>,
    #[serde(default)]
    bl_setup_base: Option<BlSetupRef>,
    cases: Vec<ViscousCase>,
}

#[derive(Debug, Deserialize)]
struct StagnationRef {
    #[serde(rename = "ist")]
    pub ist: usize,
    #[serde(rename = "sst")]
    pub sst: f64,
    #[serde(rename = "xst")]
    pub xst: f64,
    #[serde(rename = "yst")]
    pub yst: f64,
}

#[derive(Debug, Deserialize, Default)]
struct BlSetupRef {
    #[serde(rename = "ist", default)]
    pub ist: usize,
    #[serde(rename = "nbl_upper", default)]
    pub nbl_upper: usize,
    #[serde(rename = "nbl_lower", default)]
    pub nbl_lower: usize,
    #[serde(rename = "iblte_upper", default)]
    pub iblte_upper: usize,
    #[serde(rename = "iblte_lower", default)]
    pub iblte_lower: usize,
}

#[derive(Debug, Deserialize)]
struct ViscousCase {
    alpha_deg: f64,
    alpha_rad: f64,
    #[serde(default)]
    inviscid: InviscidRef,
    stagnation: StagnationRef,
    #[serde(default)]
    bl_setup: BlSetupRef,
    transitions: Vec<TransitionRef>,
    iterations: Vec<IterationRef>,
    #[serde(rename = "final", default)]
    final_result: Option<FinalResultRef>,
    #[serde(default)]
    mrchue_samples: Vec<MrchueRef>,
}

#[derive(Debug, Deserialize, Default)]
struct InviscidRef {
    cl: Option<f64>,
    gam_sample: Option<Vec<f64>>,
    qinv_sample: Option<Vec<f64>>,
}

#[derive(Debug, Deserialize)]
struct TransitionRef {
    side: i32,
    itran: usize,
    x_transition: f64,
    forced: bool,
}

#[derive(Debug, Deserialize)]
struct IterationRef {
    iteration: i32,
    rms_residual: f64,
    max_residual: f64,
    cl: f64,
    cd: f64,
    cm: f64,
}

#[derive(Debug, Deserialize, Default)]
struct FinalResultRef {
    #[serde(default)]
    cl: f64,
    #[serde(default)]
    cd: f64,
    #[serde(default)]
    cm: f64,
    #[serde(default)]
    cd_form: f64,
    #[serde(default)]
    cd_friction: f64,
    #[serde(default)]
    x_tr_upper: f64,
    #[serde(default)]
    x_tr_lower: f64,
    #[serde(default)]
    x_sep_upper: f64,
    #[serde(default)]
    x_sep_lower: f64,
    #[serde(default)]
    iterations: i32,
    #[serde(default)]
    converged: bool,
}

#[derive(Debug, Deserialize)]
struct MrchueRef {
    side: i32,
    ibl: usize,
    x: f64,
    ue: f64,
    theta: f64,
    delta_star: f64,
    hk: f64,
    cf: f64,
    transitional: bool,
}

/// Load viscous reference data from JSON file
fn load_reference() -> Option<ViscousReference> {
    // Build path from CARGO_MANIFEST_DIR (crate root) -> workspace root -> testdata
    let manifest_dir = std::env::var("CARGO_MANIFEST_DIR").ok()?;
    let workspace_root = Path::new(&manifest_dir).parent()?.parent()?;
    let ref_path = workspace_root.join("testdata").join("viscous_ref.json");
    
    if ref_path.exists() {
        let file = File::open(&ref_path).ok()?;
        let reader = BufReader::new(file);
        return serde_json::from_reader(reader).ok();
    }
    
    // Fallback: try relative paths for running from different directories
    let fallback_paths = [
        Path::new("testdata/viscous_ref.json"),
        Path::new("../../testdata/viscous_ref.json"),
    ];
    
    for path in &fallback_paths {
        if path.exists() {
            let file = File::open(path).ok()?;
            let reader = BufReader::new(file);
            return serde_json::from_reader(reader).ok();
        }
    }
    
    None
}

/// Load NACA 0012 coordinates from XFOIL-generated file
fn load_naca0012_coords() -> Option<Vec<(f64, f64)>> {
    // Build path from CARGO_MANIFEST_DIR
    let manifest_dir = std::env::var("CARGO_MANIFEST_DIR").ok()?;
    let workspace_root = Path::new(&manifest_dir).parent()?.parent()?;
    let coord_path = workspace_root.join("Xfoil-instrumented/bin/naca0012_xfoil.dat");
    
    let path = if coord_path.exists() {
        coord_path
    } else {
        // Fallback paths
        let fallback_paths = [
            Path::new("Xfoil-instrumented/bin/naca0012_xfoil.dat"),
            Path::new("../../Xfoil-instrumented/bin/naca0012_xfoil.dat"),
        ];
        fallback_paths.iter()
            .find(|p| p.exists())
            .map(|p| p.to_path_buf())?
    };
    
    let content = std::fs::read_to_string(&path).ok()?;
    let coords: Vec<(f64, f64)> = content
        .lines()
        .skip(1) // Skip header
        .filter_map(|line| {
            let parts: Vec<&str> = line.split_whitespace().collect();
            if parts.len() >= 2 {
                let x = parts[0].parse::<f64>().ok()?;
                let y = parts[1].parse::<f64>().ok()?;
                Some((x, y))
            } else {
                None
            }
        })
        .collect();
    
    if !coords.is_empty() {
        Some(coords)
    } else {
        None
    }
}

// ============================================================================
// Test Suite 1: Inviscid Inputs to Viscous Solver
// ============================================================================

#[test]
fn test_inviscid_cl_matches() {
    let ref_data = load_reference();
    if ref_data.is_none() {
        eprintln!("Skipping test: viscous_ref.json not found");
        return;
    }
    let ref_data = ref_data.unwrap();
    
    let coords = load_naca0012_coords();
    if coords.is_none() {
        eprintln!("Skipping test: NACA 0012 coordinates not found");
        return;
    }
    let coords = coords.unwrap();
    
    // Find any case with iterations
    let xfoil_case = ref_data.cases.iter()
        .find(|c| !c.iterations.is_empty());
    
    if xfoil_case.is_none() {
        eprintln!("No case with iterations found in reference data");
        return;
    }
    let xfoil_case = xfoil_case.unwrap();
    
    // Run our inviscid solver
    let result = setup_from_coords(&coords, xfoil_case.alpha_deg);
    assert!(result.is_ok(), "setup_from_coords failed: {:?}", result.err());
    let result = result.unwrap();
    
    let rustfoil_cl = result.inviscid.cl;
    
    // Check if we have pure inviscid CL from reference
    if let Some(ref_cl) = xfoil_case.inviscid.cl {
        // Compare with pure inviscid reference
        let diff_pct = ((rustfoil_cl - ref_cl) / ref_cl * 100.0).abs();
        
        println!("Inviscid CL comparison at α = {}°:", xfoil_case.alpha_deg);
        println!("  XFOIL inviscid: {:.6}", ref_cl);
        println!("  RustFoil:       {:.6}", rustfoil_cl);
        println!("  Difference:     {:.2}%", diff_pct);
        
        assert!(diff_pct < 1.0, 
            "Inviscid CL differs by {:.2}% (XFOIL: {}, RustFoil: {})",
            diff_pct, ref_cl, rustfoil_cl);
    } else {
        // No pure inviscid reference - compare with first viscous iteration
        // Note: Viscous effects reduce CL by ~8-10%, so we use a looser tolerance
        if let Some(first_iter) = xfoil_case.iterations.first() {
            let xfoil_visc_cl = first_iter.cl;
            let diff_pct = ((rustfoil_cl - xfoil_visc_cl) / xfoil_visc_cl * 100.0).abs();
            
            println!("Inviscid CL comparison at α = {}° (vs viscous iter 1):", xfoil_case.alpha_deg);
            println!("  XFOIL (visc iter 1): {:.6}", xfoil_visc_cl);
            println!("  RustFoil (inviscid): {:.6}", rustfoil_cl);
            println!("  Difference:          {:.2}% (expected ~8-10% due to viscous effects)", diff_pct);
            
            // Pure inviscid CL is typically 8-10% higher than viscous CL
            // So RustFoil should be higher than XFOIL viscous iter 1
            assert!(rustfoil_cl > xfoil_visc_cl,
                "Inviscid CL should be higher than viscous CL");
            assert!(diff_pct < 15.0, 
                "Inviscid CL differs by {:.2}% from viscous (expected <15%)",
                diff_pct);
        }
    }
}

#[test]
fn test_stagnation_point_matches() {
    let ref_data = load_reference();
    if ref_data.is_none() {
        eprintln!("Skipping test: viscous_ref.json not found");
        return;
    }
    let ref_data = ref_data.unwrap();
    
    let coords = load_naca0012_coords();
    if coords.is_none() {
        eprintln!("Skipping test: NACA 0012 coordinates not found");
        return;
    }
    let coords = coords.unwrap();
    
    // Find the converged case
    let converged_case = ref_data.cases.iter()
        .find(|c| c.final_result.as_ref().map_or(false, |f| f.converged));
    
    if converged_case.is_none() {
        return;
    }
    let xfoil_case = converged_case.unwrap();
    
    // Run our solver
    let result = setup_from_coords(&coords, xfoil_case.alpha_deg);
    assert!(result.is_ok());
    let result = result.unwrap();
    
    // Compare stagnation point
    let xfoil_stag = &xfoil_case.stagnation;
    
    println!("Stagnation point comparison at α = {}°:", xfoil_case.alpha_deg);
    println!("  XFOIL IST: {}, RustFoil: {}", xfoil_stag.ist, result.ist);
    println!("  XFOIL SST: {:.6}, RustFoil: {:.6}", xfoil_stag.sst, result.sst);
    
    // IST should be within ±2 panels (stagnation point detection is sensitive)
    let ist_diff = (result.ist as i32 - xfoil_stag.ist as i32).abs();
    assert!(ist_diff <= 2, 
        "IST differs by {} (XFOIL: {}, RustFoil: {})", 
        ist_diff, xfoil_stag.ist, result.ist);
    
    // SST should be within 1% of total arc length
    let total_arc = result.setup.arc_lengths.last().copied().unwrap_or(1.0);
    let sst_diff = ((result.sst - xfoil_stag.sst) / total_arc * 100.0).abs();
    assert!(sst_diff < 1.0, 
        "SST differs by {:.2}% of total arc (XFOIL: {}, RustFoil: {})", 
        sst_diff, xfoil_stag.sst, result.sst);
}

// ============================================================================
// Test Suite 2: Surface Extraction
