#[test]
fn test_surface_counts_match() {
    let ref_data = load_reference();
    if ref_data.is_none() {
        eprintln!("Skipping test: viscous_ref.json not found");
        return;
    }
    let ref_data = ref_data.unwrap();
    
    let coords = load_naca0012_coords();
    if coords.is_none() {
        return;
    }
    let coords = coords.unwrap();
    
    // Run solver at alpha = 4 deg
    let result = setup_from_coords(&coords, 4.0);
    assert!(result.is_ok());
    let result = result.unwrap();
    
    // Count our surfaces
    let n_total = result.setup.arc_lengths.len();
    let n_upper = result.setup.n_upper;
    let n_lower = result.setup.n_lower;
    
    println!("Surface node counts:");
    println!("  Total: {}", n_total);
    println!("  Upper: {}", n_upper);
    println!("  Lower: {}", n_lower);
    println!("  Stagnation index: {}", result.ist);
    
    // Sanity checks
    assert!(n_upper > 0, "Upper surface should have nodes");
    assert!(n_lower > 0, "Lower surface should have nodes");
    assert_eq!(n_upper + n_lower - 1, n_total, 
        "Upper + lower - 1 (stag shared) should equal total");
}

// ============================================================================
// Test Suite 3: Arc Length Computation
// ============================================================================

#[test]
fn test_arc_lengths_positive() {
    let coords = load_naca0012_coords();
    if coords.is_none() {
        return;
    }
    let coords = coords.unwrap();
    
    let x: Vec<f64> = coords.iter().map(|(x, _)| *x).collect();
    let y: Vec<f64> = coords.iter().map(|(_, y)| *y).collect();
    
    let arc = compute_arc_lengths(&x, &y);
    
    // Arc lengths should be monotonically increasing
    for i in 1..arc.len() {
        assert!(arc[i] >= arc[i-1], 
            "Arc length decreased at index {}: {} -> {}", 
            i, arc[i-1], arc[i]);
    }
    
    // First should be 0
    assert!((arc[0] - 0.0).abs() < 1e-10, "First arc length should be 0");
    
    // Total should be > 2 (chord = 1, so perimeter > 2)
    let total = arc.last().copied().unwrap_or(0.0);
    assert!(total > 2.0, "Total arc length {} should be > 2 for unit chord", total);
}

// ============================================================================
// Test Suite 4: MRCHUE Initial BL State - Surface Extraction Validation
// ============================================================================

use rustfoil_solver::viscous::extract_surface_xfoil;

/// Test that surface extraction produces correct arc lengths and Ue values
/// matching XFOIL's IBLPAN + XICALC output.
///
/// This validates the fix to extract_surface_xfoil() which should NOT include
/// the stagnation panel (IST) itself, only panels IST-1 down to 0 for upper surface.
#[test]
fn test_surface_extraction_matches_xfoil() {
    let ref_data = load_reference();
    if ref_data.is_none() {
        eprintln!("Skipping test: viscous_ref.json not found");
        return;
    }
    let ref_data = ref_data.unwrap();
    
    let coords = load_naca0012_coords();
    if coords.is_none() {
        eprintln!("Skipping test: NACA 0012 coordinates not found");
        return;
    }
    let coords = coords.unwrap();
    
    // Find case with MRCHUE samples
    let case = ref_data.cases.iter()
        .find(|c| !c.mrchue_samples.is_empty());
    
    if case.is_none() {
        eprintln!("No MRCHUE samples in reference data");
        return;
    }
    let case = case.unwrap();
    
    // Run our setup
    let result = setup_from_coords(&coords, case.alpha_deg);
    assert!(result.is_ok(), "setup_from_coords failed: {:?}", result.err());
    let result = result.unwrap();
    
    // Extract surfaces using the same function the CLI uses
    let full_arc = &result.setup.arc_lengths;
    let node_x = &result.node_x;
    let node_y = &result.node_y;
    let ue_inviscid = &result.inviscid.gamma;
    let ist = result.ist;
    let sst = result.sst;
    
    // Interpolate Ue at stagnation
    let ue_stag = if ist + 1 < ue_inviscid.len() && full_arc[ist + 1] != full_arc[ist] {
        let frac = (sst - full_arc[ist]) / (full_arc[ist + 1] - full_arc[ist]);
        ue_inviscid[ist] + frac * (ue_inviscid[ist + 1] - ue_inviscid[ist])
    } else {
        ue_inviscid[ist]
    };
    
    let (upper_arc, _upper_x, _upper_y, upper_ue) = extract_surface_xfoil(
        ist, sst, ue_stag, full_arc, node_x, node_y, ue_inviscid, true
    );
    
    println!("\nSurface extraction results:");
    println!("  IST = {}, SST = {:.6}", ist, sst);
    println!("  Upper surface: {} stations", upper_arc.len());
    println!("  Station 0 (virtual stag): arc={:.6}, Ue={:.6}", upper_arc[0], upper_ue[0]);
    
    // Compare with XFOIL MRCHUE samples (side=1 is upper surface)
    let upper_samples: Vec<_> = case.mrchue_samples.iter()
        .filter(|s| s.side == 1)
        .collect();
    
    if upper_samples.is_empty() {
        eprintln!("No upper surface samples in reference data");
        return;
    }
    
    println!("\nComparison with XFOIL MRCHUE (first 5 stations):");
    println!("{:>4} {:>12} {:>12} {:>12} {:>12} {:>10}", 
        "IBL", "XFOIL arc", "Rust arc", "XFOIL Ue", "Rust Ue", "arc err%");
    
    // IBL=2 in XFOIL corresponds to index 1 in our array (index 0 is virtual stagnation)
    for sample in upper_samples.iter().take(5) {
        let rust_idx = sample.ibl - 1; // IBL is 1-indexed, our array is 0-indexed
        
        if rust_idx >= upper_arc.len() {
            eprintln!("  IBL {} out of range (have {} stations)", sample.ibl, upper_arc.len());
            continue;
        }
        
        let rust_arc = upper_arc[rust_idx];
        let rust_ue = upper_ue[rust_idx];
        let xfoil_arc = sample.x;
        let xfoil_ue = sample.ue;
        
        let arc_err = if xfoil_arc > 1e-10 {
            ((rust_arc - xfoil_arc) / xfoil_arc * 100.0).abs()
        } else {
            0.0
        };
        
        println!("{:>4} {:>12.6} {:>12.6} {:>12.6} {:>12.6} {:>9.1}%", 
            sample.ibl, xfoil_arc, rust_arc, xfoil_ue, rust_ue, arc_err);
    }
    
    // Check that station 2 (IBL=2, index 1) arc length is close to XFOIL
    // XFOIL IBL=2 has x ≈ 0.0011
    if let Some(sample2) = upper_samples.iter().find(|s| s.ibl == 2) {
        let rust_arc = upper_arc.get(1).copied().unwrap_or(0.0);
        let rust_ue = upper_ue.get(1).copied().unwrap_or(0.0);
        
        let arc_diff_pct = ((rust_arc - sample2.x) / sample2.x * 100.0).abs();
        let ue_diff_pct = ((rust_ue - sample2.ue) / sample2.ue * 100.0).abs();
        
        println!("\nStation 2 (IBL=2) validation:");
        println!("  Arc: XFOIL={:.6}, RustFoil={:.6}, diff={:.1}%", 
            sample2.x, rust_arc, arc_diff_pct);
        println!("  Ue:  XFOIL={:.6}, RustFoil={:.6}, diff={:.1}%", 
            sample2.ue, rust_ue, ue_diff_pct);
        
        // Arc length should be within 50% (we're validating the fix worked)
        // A 100x error (which existed before) will clearly fail this
        assert!(arc_diff_pct < 50.0, 
            "Station 2 arc differs by {:.1}% (XFOIL: {}, RustFoil: {}). \
            This suggests extract_surface_xfoil is not excluding the stagnation panel.",
            arc_diff_pct, sample2.x, rust_arc);
        
        // Ue should be within order of magnitude
        assert!(ue_diff_pct < 100.0,
            "Station 2 Ue differs by {:.1}% (XFOIL: {}, RustFoil: {})",
            ue_diff_pct, sample2.ue, rust_ue);
    }
}

