#[test]
fn test_reference_data_loads() {
    let ref_data = load_reference();
    
    if ref_data.is_none() {
        eprintln!("Note: Reference data not found. Run:");
        eprintln!("  python scripts/extract_viscous_reference.py");
        return;
    }
    
    let ref_data = ref_data.unwrap();
    
    println!("Loaded reference data:");
    println!("  Source: {}", ref_data.source);
    println!("  Airfoil: {}", ref_data.airfoil);
    println!("  Panels: {}", ref_data.n_panels);
    println!("  Reynolds: {:.2e}", ref_data.reynolds);
    println!("  Cases: {}", ref_data.cases.len());
    
    // Find converged case
    let converged = ref_data.cases.iter()
        .filter(|c| c.final_result.as_ref().map_or(false, |f| f.converged))
        .count();
    println!("  Converged cases: {}", converged);
}

#[test]
fn test_naca0012_coords_load() {
    let coords = load_naca0012_coords();
    
    if coords.is_none() {
        eprintln!("Note: NACA 0012 coordinate file not found.");
        eprintln!("Generate with XFOIL: NACA 0012, SAVE");
        return;
    }
    
    let coords = coords.unwrap();
    println!("Loaded NACA 0012 coordinates: {} points", coords.len());
    
    // Basic validation
    assert!(coords.len() >= 50, "Should have at least 50 points");
    
    // Should start and end near x=1 (TE)
    let (first_x, _) = coords.first().unwrap();
    let (last_x, _) = coords.last().unwrap();
    assert!(*first_x > 0.99, "First point should be near TE");
    assert!(*last_x > 0.99, "Last point should be near TE");
    
    // Should have LE near x=0
    let has_le = coords.iter().any(|(x, _)| *x < 0.01);
    assert!(has_le, "Should have points near leading edge");
}
